<?php namespace App\Repositories\Student;use App\Repositories\BaseRepository;use App\Models\Student\StudentPromotion;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class StudentPromotionRepository extends BaseRepository{    public function __construct(StudentPromotion $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByStudent(int $studentId): Collection    {        return $this->findByField('student_id', $studentId);    }    public function findByAcademicYear(int $academicYearId): Collection    {        return $this->findByField('academic_year_id', $academicYearId);    }    public function findByFromClass(int $classId): Collection    {        return $this->findByField('from_class_id', $classId);    }    public function findByToClass(int $classId): Collection    {        return $this->findByField('to_class_id', $classId);    }    public function getByStatus(string $status): Collection    {        return $this->findByField('status', $status);    }    public function getPromotionsByYear(int $academicYearId): Collection    {        return $this->query()->where('academic_year_id', $academicYearId)->with(['student', 'fromClass', 'toClass'])->get();    }    public function countPromotedByClass(int $academicYearId): Collection    {        return $this->query()->selectRaw('to_class_id, COUNT(*) as total')->where('academic_year_id', $academicYearId)->where('status', 'promoted')->groupBy('to_class_id')->get();    }    public function promoteStudents(array $studentIds, int $fromClassId, int $toClassId, int $academicYearId, array $data = []): Collection    {        $promotions = collect();        foreach ($studentIds as $studentId) {            $promotions->push($this->create(array_merge($data, [                'student_id' => $studentId,                'from_class_id' => $fromClassId,                'to_class_id' => $toClassId,                'academic_year_id' => $academicYearId,                'status' => 'promoted',                'promotion_date' => now(),            ])));        }        return $promotions;    }}